"use client";

import { X } from "lucide-react";
import Image from "next/image";
import Link from "next/link";
import { useRouter, useSearchParams } from "next/navigation";
import { useEffect, useState } from "react";
import { Dialog, DialogContent, DialogTrigger } from "@/components/ui/dialog";
import { welcomeBannerContent } from "@/constants/welcomeBanner";
import { useCredits } from "@/context/CreditProvider";
import { authClient } from "@/lib/auth-client";
import Logo from "@/public/assets/icons/LeftSidebar/Logo.svg";

// Persistent storage key prefix
const BANNER_CLOSED_KEY = "Showcart_welcome_banner_closed_";

export default function WelcomeBanner() {
  const searchParams = useSearchParams();
  const router = useRouter();
  const { data: session } = authClient.useSession();
  const user = session?.user;
  const { refreshCredits } = useCredits();

  const [currentImageIndex, setCurrentImageIndex] = useState<number>(0);
  const [showBanner, setShowBanner] = useState<boolean>(false);

  // Prevent body scroll when banner is visible
  useEffect(() => {
    if (showBanner) {
      document.body.style.overflow = "hidden";
    } else {
      document.body.style.overflow = "unset";
    }

    // Cleanup function to restore scroll when component unmounts
    return () => {
      document.body.style.overflow = "unset";
    };
  }, [showBanner]);

  // Check localStorage and URL params to determine if banner should be shown
  useEffect(() => {
    if (!user?.id) return;
    // Generate storage key specific to this user
    const storageKey = `${BANNER_CLOSED_KEY}${user.id}`;

    // If URL explicitly sets showBanner parameter, use that setting
    if (searchParams.has("showBanner")) {
      const shouldShow = searchParams.get("showBanner") === "true";
      setShowBanner(shouldShow);

      // If explicitly set to false, also save to localStorage
      if (!shouldShow) {
        try {
          localStorage.setItem(storageKey, "true");
        } catch (e) {
          console.error("Failed to save banner state to localStorage:", e);
        }
      }
      return;
    }

    // Check if user has previously closed the banner
    try {
      const bannerClosed = localStorage.getItem(storageKey) === "true";

      // If not closed before, check if user is new
      if (!bannerClosed && user?.createdAt) {
        // Check if user is new (e.g., created within last 10 minutes)
        const userCreatedAt = new Date(user.createdAt);
        const tenMinutesAgo = new Date(Date.now() - 10 * 60 * 1000);

        if (userCreatedAt > tenMinutesAgo) {
          setShowBanner(true);
          const params = new URLSearchParams(searchParams.toString());
          params.set("showBanner", "true");
          router.push(`?${params.toString()}`, { scroll: false });
        }
      }
    } catch (e) {
      console.error("Error accessing localStorage:", e);
    }
  }, [user?.id, user, searchParams, router]);

  const handleNextImage = () => {
    setCurrentImageIndex((currentImageIndex + 1) % welcomeBannerContent.length);
  };

  const handlePreviousImage = () => {
    setCurrentImageIndex(
      (currentImageIndex - 1 + welcomeBannerContent.length) %
        welcomeBannerContent.length,
    );
  };

  const handleClose = () => {
    setShowBanner(false);

    // Update URL params
    const params = new URLSearchParams(searchParams.toString());
    params.set("showBanner", "false");
    router.push(`?${params.toString()}`, { scroll: false });

    // Save to localStorage if user is available
    if (user?.id) {
      try {
        localStorage.setItem(`${BANNER_CLOSED_KEY}${user.id}`, "true");
      } catch (e) {
        console.error("Failed to save banner state to localStorage:", e);
      }
    }

    // ⚡ OPTIMIZATION: Fire-and-forget credit refresh when banner closes
    // By this time, webhook has had 3-5 seconds to complete (user viewed slides)
    // This ensures metadata is ready and credits load reliably
    const refreshCreditsInBackground = async () => {
      try {
        await refreshCredits();
      } catch (error) {
        console.error("❌ Error refreshing credits on banner close:", error);
      }
    };

    // Fire and forget - don't wait (banner closes immediately)
    refreshCreditsInBackground();
  };

  if (!showBanner) return null;

  return (
    <Dialog onOpenChange={setShowBanner} open={showBanner}>
      <DialogContent className="no-scrollbar m-0 min-h-screen w-full max-w-none flex-center overflow-y-scroll rounded-none border-0 bg-black/40 bg-blur-sm p-0 outline-none">
        <DialogTrigger className="hidden" />

        <div className="relative grid h-[90vh] max-h-[665px] w-[95vw] max-w-[930px] overflow-x-hidden overflow-y-scroll rounded-xl bg-[#101010] lg:grid-cols-2">
          <div className="relative col-span-1 overflow-hidden max-lg:hidden">
            <Image
              alt="image-generator"
              className="h-full w-full object-cover opacity-50"
              height={382}
              src="https://d2weamipq0hk4d.cloudfront.net/assets/asset_1766735085874.webp"
              width={676}
            />
            <Link className="absolute top-7 left-7 flex-start gap-3" href="/">
              <Image
                alt="Logo"
                className="h-7"
                height={30}
                src="/assets/icons/LeftSidebar/WordMark.svg"
                width={200}
              />
            </Link>
            <div className="absolute inset-x-0 bottom-7 flex w-full flex-col items-start gap-[22px] px-7 text-white">
              <div className="font-semibold text-2xl leading-[40px] tracking-[-0.857px] md:text-[34px]">
                Welcome to showcart
              </div>
              <div className="text-xs md:text-sm">
                Thank you for joining us You&apos;re now part of an exclusive
                club of the first 20,000 users.
              </div>
            </div>
          </div>
          <div className="col-span-1 flex flex-col items-center justify-between p-3">
            <div className="flex w-full items-center justify-end">
              <button onClick={handleClose} type="button">
                <X className="size-4 cursor-pointer text-white" />
              </button>
            </div>
            <div className="flex w-full flex-col items-center gap-7">
              <div className="flex flex-col gap-2.5">
                <div className="bg-gradient-to-r from-[#999999] via-white to-[#999999] bg-clip-text text-center font-semibold text-2xl text-transparent tracking-[-0.857px] md:text-[34px] md:leading-[40px]">
                  {welcomeBannerContent[currentImageIndex].title}{" "}
                </div>
                <div className="text-center text-text-500 text-xs md:text-sm">
                  {welcomeBannerContent[currentImageIndex].description}{" "}
                </div>
              </div>
              <Image
                alt="image-generator"
                className="h-fit w-full object-contain"
                height={382}
                src={welcomeBannerContent[currentImageIndex].image}
                width={676}
              />
            </div>
            <div className="flex w-full flex-center flex-col justify-center gap-5">
              <div className="mx-auto flex items-center justify-start gap-3">
                {welcomeBannerContent.map((_, index) => (
                  <button
                    aria-current={currentImageIndex === index}
                    aria-label={`Go to image ${index + 1}`}
                    className={`h-[5px] w-[23px] cursor-pointer rounded-full transition-colors ${currentImageIndex === index ? "bg-white" : "bg-background-100"} `}
                    key={`${index}-${currentImageIndex}`}
                    onClick={() => setCurrentImageIndex(index)}
                    title="Go to Image"
                    type="button"
                  />
                ))}
              </div>
              <div className="w-full flex-between">
                <button
                  className="flex-center cursor-pointer text-nowrap rounded-[10px] bg-background-400 px-5 py-3 text-h5 text-white transition-all duration-300 hover:bg-background-400/80 disabled:cursor-not-allowed disabled:opacity-50"
                  disabled={currentImageIndex === 0}
                  onClick={handlePreviousImage}
                  type="button"
                >
                  Back
                </button>
                <button
                  className="flex-center cursor-pointer text-nowrap rounded-[10px] bg-highlight-500 px-5 py-3 text-h5 text-white transition-all duration-300 hover:bg-highlight-500/80"
                  onClick={
                    currentImageIndex === welcomeBannerContent.length - 1
                      ? handleClose
                      : handleNextImage
                  }
                  type="button"
                >
                  {currentImageIndex === welcomeBannerContent.length - 1
                    ? "Finish"
                    : "Next"}
                </button>
              </div>
            </div>
          </div>
        </div>
      </DialogContent>
    </Dialog>
  );
}
